function initFullSection() {
    // 1. Renderizar tarjetas
    const container = document.getElementById('lq-ag-timeline');
    if (container) {
        let html = '';
        FULL_AGENDA.forEach(item => {
            let iconToUse;
            if (item.speaker && item.speaker.toLowerCase().includes('patricia')) {
                iconToUse = PATRICIA_ICON;
            } else if (item.iconType === 'william') {
                iconToUse = WILLIAM_ICON;
            } else if (item.iconType === 'pantera') {
                iconToUse = DORA_ICON; // Fallback to default styling for now as requested just logo in card
            } else {
                iconToUse = DORA_ICON;
            }
            const reqHtml = typeof item.requirements === 'object'
                ? `<div class="lq-ag-req-box">
                     <span class="req-label" data-i18n="agenda.req.label">Requisitos:</span>
                     <a href="${item.requirements.link}" target="_blank" class="req-btn-link" data-i18n="${item.requirements.textKey}">${item.requirements.text}</a>
                   </div>`
                : `<div class="lq-ag-req-box">
                     <span class="req-label" data-i18n="agenda.req.label">Requisitos:</span>
                     <span class="req-text" data-i18n="${item.reqKey}">${item.requirements || 'Libres'}</span>
                   </div>`;

            html += `
            <div class="lq-ag-card">
          
                <div class="lq-ag-time-box ${item.specialIcon ? 'special-time-box' : ''}">
                    
                    <div class="time-content">
                  
                        <span class="lq-ag-start">${item.time}</span>
                        
                        <span class="lq-ag-end">${item.end}</span>
                    </div>
                </div>
                <div class="lq-ag-info-box">
                    <span class="lq-ag-badge" data-i18n="${item.typeKey}">${item.type}</span>
                    <h3 class="lq-ag-event-name" data-i18n="${item.titleKey}">${item.title}</h3>
                    <div class="lq-ag-speaker" ${item.speakerKey ? `data-i18n="${item.speakerKey}"` : ''}> ${item.speaker}</div>
                    ${reqHtml}
                </div>
                <div class="lq-ag-actions">
                    ${makeBtn('meet', item.links.meet)}
                    ${makeBtn('yt', item.links.yt)}
                    ${makeBtn('fb', item.links.fb)}
                </div>
            </div>`;
        });
        container.innerHTML = html;

        // Activar la interacción de la gota
        activateWaterRipple();

        // Iniciar el fondo de partículas
        initBackgroundCanvas();

        // Aplicar traducciones a los nuevos elementos
        if (window.setLanguage) {
            const currentLang = localStorage.getItem('user_lang') || 'es';
            window.setLanguage(currentLang);
        }
    }
}


function makeBtn(type, link) {
    const isInactive = !link || link === '#';
    const style = isInactive ? 'opacity: 0.3; cursor: default;' : '';
    // Agregamos clase específica para el glow (btn-meet, btn-yt, btn-fb)
    return `<button class="lq-ag-btn btn-${type}" data-link="${link}" style="${style}">
                ${SVG_ICONS[type]}
            </button>`;
}

// === LÓGICA DE LA ANIMACIÓN DE GOTA ===
function activateWaterRipple() {
    const buttons = document.querySelectorAll('.lq-ag-btn');

    buttons.forEach(btn => {
        btn.addEventListener('click', function (e) {
            e.preventDefault();
            const link = this.getAttribute('data-link');
            if (!link || link === '#' || link === 'undefined') return;

            // Coordenadas del click dentro del botón
            const rect = this.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            // Crear el elemento de la gota
            const drop = document.createElement('span');
            drop.classList.add('water-drop');
            // Tamaño grande para cubrir
            const size = Math.max(rect.width, rect.height) * 2.5;
            drop.style.width = drop.style.height = `${size}px`;
            drop.style.left = `${x - size / 2}px`;
            drop.style.top = `${y - size / 2}px`;

            // Limpiar anteriores
            const old = this.querySelector('.water-drop');
            if (old) old.remove();

            this.appendChild(drop);
            this.classList.add('clicked'); // Efecto rebote

            // ESPERAR ANIMACIÓN (1.2s)
            setTimeout(() => {
                window.open(link, '_blank');

                // Limpiar
                setTimeout(() => {
                    this.classList.remove('clicked');
                    if (drop) drop.remove();
                }, 500);
            }, 1200);
        });
    });
}

// === FONDO DE NEBULOSA (CANVAS) ===
function initBackgroundCanvas() {
    const canvas = document.getElementById('lq-ag-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let w, h;
    const particles = [];

    function resize() {
        w = canvas.width = canvas.offsetWidth;
        h = canvas.height = canvas.offsetHeight;
        initP();
    }

    class Particle {
        constructor() {
            this.x = Math.random() * w;
            this.y = Math.random() * h;
            this.vx = (Math.random() - 0.5) * 0.5;
            this.vy = (Math.random() - 0.5) * 0.5;
            this.size = Math.random() * 80 + 40;
            this.color = `rgba(212, 165, 116, ${Math.random() * 0.2 + 0.05})`;
        }
        update() {
            this.x += this.vx; this.y += this.vy;
            if (this.x < 0 || this.x > w) this.vx *= -1;
            if (this.y < 0 || this.y > h) this.vy *= -1;
        }
        draw() {
            const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.size);
            g.addColorStop(0, this.color);
            g.addColorStop(1, 'rgba(0,0,0,0)');
            ctx.fillStyle = g;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    function initP() {
        particles.length = 0;
        for (let i = 0; i < 20; i++) particles.push(new Particle());
    }

    function animate() {
        ctx.clearRect(0, 0, w, h);
        ctx.globalCompositeOperation = 'screen';
        particles.forEach(p => { p.update(); p.draw(); });
        ctx.globalCompositeOperation = 'source-over';
        requestAnimationFrame(animate);
    }

    window.addEventListener('resize', resize);
    resize();
    animate();
}